#!/bin/bash

set -e

# Function to authenticate with AWS
authenticate() {
    if [ -z "$AWS_ACCESS_KEY_ID" ] || [ -z "$AWS_SECRET_ACCESS_KEY" ]; then
        echo "AWS credentials not set. Please set AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY."
        exit 1
    fi

    export AWS_REGION=${AWS_REGION:-us-east-1}
    echo "Authenticated to AWS in region: $AWS_REGION"
}

# Function to deploy application
deploy() {
    local stack_name=$1
    local template_file=$2
    local parameters_file=$3

    echo "Deploying stack: $stack_name"
    aws cloudformation deploy \
        --template-file "$template_file" \
        --stack-name "$stack_name" \
        --parameter-overrides "$(cat "$parameters_file")" \
        --capabilities CAPABILITY_IAM
}

# Main script execution
main() {
    authenticate

    if [ "$#" -ne 3 ]; then
        echo "Usage: $0 <stack_name> <template_file> <parameters_file>"
        exit 1
    fi

    deploy "$1" "$2" "$3"
}

main "$@"